    var body: some View {
        VStack {
            Text("Reset Your Password")
                .font(.largeTitle)
                .padding()

            Text("Token: \(token)")
                .font(.caption)
                .foregroundColor(.gray)
                .padding(.bottom)

            SecureField("New Password", text: $newPassword)
                .textFieldStyle(RoundedBorderTextFieldStyle())
                .padding(.horizontal)
                .autocapitalization(.none)

            SecureField("Confirm Password", text: $confirmPassword)
                .textFieldStyle(RoundedBorderTextFieldStyle())
                .padding(.horizontal)
                .padding(.bottom)
                .autocapitalization(.none)

            Button("Reset Password") {
                resetPassword()
            }
            .buttonStyle(BorderedProminentButtonStyle())
            .padding()

            Text(message)
                .foregroundColor(message.contains("Success") ? .green : .red)
                .padding()

            Spacer()
        }
        .navigationTitle("Password Reset")
        .navigationBarTitleDisplayMode(.inline)
    }

    private func resetPassword() {
        guard newPassword == confirmPassword else {
            message = "Passwords do not match."
            return
        }

        guard !newPassword.isEmpty else {
            message = "Password cannot be empty."
            return
        }

        // In a real app, you would send the token and newPassword to your backend API
        // For demonstration, we'll just simulate a success/failure
        print("Attempting to reset password with token: \(token) and new password: \(newPassword)")

        // Simulate API call
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) {
            if token.hasPrefix("valid") { // Simulate a valid token
                message = "Password reset successfully! You can now log in."
                newPassword = ""
                confirmPassword = ""
            } else {
                message = "Password reset failed. Invalid or expired token."
            }
        }
    }
}

enum AppLink: Identifiable, Hashable {
    case passwordReset(token: String)
    case otherLink
