}

struct ContentView: View {
    @State private var activeLink: AppLink?

    var body: some View {
        NavigationStack {
            VStack {
                Image(systemName: "lock.fill")
                    .resizable()
                    .scaledToFit()
                    .frame(width: 100, height: 100)
