                    handleUniversalLink(url: simulatedURL)
                }
                .buttonStyle(BorderedProminentButtonStyle())
                .padding()

                if let link = activeLink {
                    NavigationLink(value: link) {
                        EmptyView()
                    }
                    .opacity(0) // Hide the NavigationLink visually
                    .frame(width: 0, height: 0)
                }
            }
            .navigationDestination(for: AppLink.self) { link in
                switch link {
                case .passwordReset(let token):
                    PasswordResetView(token: token)
                case .otherLink:
                    Text("Other Link Content")
                }
            }
        }
        .onOpenURL { url in
            handleUniversalLink(url: url)
        }
    }

    private func handleUniversalLink(url: URL) {
        guard url.scheme == "https" || url.scheme == "http",
              url.host == "myapp.com" else {
            print("Not a universal link for myapp.com or invalid scheme: \(url)")
            return
        }

        let pathComponents = url.pathComponents
        print("Received URL: \(url)")
        print("Path components: \(pathComponents)")

        if pathComponents.contains("reset-password") {
            if let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
               let queryItems = components.queryItems {
                for item in queryItems {
                    if item.name == "token", let token = item.value {
                        print("Found password reset token: \(token)")
                        activeLink = .passwordReset(token: token)
                        return
                    }
                }
            }
            print("Password reset link found, but no token parameter.")
        } else {
            print("Unhandled universal link path: \(url.path)")
            // Handle other universal links or default behavior
            activeLink = .otherLink // Example for other links
        }
    }
}

